  ('disabled-57f41407-moex-00549', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '受命法官於第一次審判期日前，傳喚被告或其代理人，並通知檢察官、 辯護人、輔佐人到庭，行準備程序時，不得為下列何事項之處理？', '["起訴效力所及之範圍與有無應變更檢察官所引應適用法條之情形", "訊問被告、代理人及辯護人對檢察官起訴事實是否為認罪之答辯", "關於爭議證據能力有無之認定，由受命法官直接裁定", "命提出證物或可為證據之文書"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00550', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '依刑事訴訟法規定，上訴期間為幾日？', '["5日", "7日", "10日", "20日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00551', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於聲請再審，下列敘述何者正確？', '["聲請再審，應委任律師為代理人", "為受判決人之不利益聲請再審，於判決確定後，經過20日者，不得為之", "受有罪判決之人已證明其係被誣告，得聲請再審", "聲請再審應由檢察總長提起"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00552', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於兒童權利公約施行法，下列敘述何者錯誤？', '["屬國內法", "屬國際法", "屬公法", "屬成文法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00553', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '臺灣社會在歷史上曾長期受到傳統中國法直接與間接影響，下列關於傳統 中國法之敘述，何者錯誤？', '["傳統中國法有以家族倫理秩序來制定規範的特色", "人民間發生紛爭而向官府提起控告時，是由地方官員進行審案", "人民若不服地方官員的審案結果，並無任何救濟的方式", "傳統中國法體系中有成文法之存在"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00554', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於法院與行政機關之適用法律，下列敘述何者錯誤？', '["法院適用法律不受上級機關之指揮監督", "行政機關適用法律不受上級機關之指揮監督", "法院適用法律應遵守不告不理原則", "行政機關適用法律並無不告不理原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00555', 'disabled-57f41407', 'disabled-57f41407-moex-111-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '依平等原則，「相同之事件，應為相同之處理」，其所適用的法律補充方 法，為「類推適用」。反之，針對「不同之事件，應為不同之處理」所適 用之法律補充方法，為下述何者？', '["論理解釋", "目的性限縮", "目的性擴張", "類推解釋"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "6dac6e4ea24d", "answer_pdf_sha1": "6ce7edc90a97", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
